const prompt = `Rewrite to maximize ATS without hallucinating.

Original Resume:
${JSON.stringify(input.original_resume)}

Job Description:
${input.job.title} - ${input.job.description || ''}

Missing Keywords:
${input.ats.gap_analysis.missing_mandatory_skills.join(', ')}

Recommendations:
${JSON.stringify(input.ats.optimization_recommendations)}`;

return [{
  json: {
    input,
    prompt,
    model: $env.MODEL_RESUME_OPTIMIZATION || 'anthropic/claude-3.5-sonnet'
  }
}];

