const req = $('Build Prompt').item.json.input;
const original = req.original_resume;
const llmRes = $input.first().json;

let parsed;
try {
  parsed = JSON.parse(llmRes.choices[0].message.content);
} catch (e) {
  throw new Error('LLM output was not valid JSON');
}

const tailored = parsed.tailored_resume;
let status = 'OPTIMIZED';
let failReason = null;

// SAFETY VALIDATION
// 1. Check if experience count changed (hallucination)
const origExpCount = (original.experience || []).length;
const newExpCount = (tailored.experience || []).length;
if (origExpCount !== newExpCount) {
  status = 'VALIDATION_FAILED';
  failReason = 'LLM altered the number of experience entries.';
}

// 2. Check if companies match
if (status === 'OPTIMIZED') {
  const origCompanies = (original.experience || []).map(e => e.company.toLowerCase());
  const newCompanies = (tailored.experience || []).map(e => e.company.toLowerCase());
  for (let i = 0; i < origCompanies.length; i++) {
    if (origCompanies[i] !== newCompanies[i]) {
      status = 'VALIDATION_FAILED';
      failReason = `Company mismatch at index ${i}: ${origCompanies[i]} vs ${newCompanies[i]}`;
      break;
    }
  }
}

// 3. Check Education
if (status === 'OPTIMIZED') {
  const origEduCount = (original.education || []).length;
  const newEduCount = (tailored.education || []).length;
  if (origEduCount !== newEduCount) {
    status = 'VALIDATION_FAILED';
    failReason = 'LLM altered education history.';
  }
}

return [{
  json: {
    status,
    validation_report: { passed: status === 'OPTIMIZED', reason: failReason },
    tailored_resume: tailored,
    change_log: parsed.change_log
  }
}];
